window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["c36-plumbing"] = window.COURSE_LANG["c36-plumbing"] || {};
window.COURSE_LANG["c36-plumbing"]["es"] = [
  {"id":1,"q":"¿Qué tubo de cobre tiene la pared más gruesa y se prefiere para la acometida de agua enterrada?","opts":["Tipo K","Tipo L","Tipo M","Cobre DWV"],"re":"El tipo K tiene la pared más gruesa de los tubos de agua comunes, por eso se usa enterrado y en alta presión."},
  {"id":2,"q":"El tubo rígido de CPVC y PVC normalmente se une mediante:","opts":["Soldadura con fundente","Cemento solvente (con imprimante en PVC/CPVC)","Solo coples roscados","Anillos de engargolado"],"re":"El PVC y el CPVC se unen con cemento solvente; el solvente ablanda y funde el plástico en una sola pieza."},
  {"id":3,"q":"¿Qué tubo plástico está clasificado para distribución de agua caliente y fría dentro de un edificio?","opts":["PVC","ABS","CPVC","Hierro fundido"],"re":"El CPVC es PVC clorado formulado para soportar agua caliente; el PVC simple no está clasificado para agua caliente."},
  {"id":4,"q":"La tubería de agua PEX comúnmente se une usando:","opts":["Cemento solvente","Juntas de plomo y estopa","Soldadura fuerte (brazing)","Conexiones de engargolado, expansión o a presión"],"re":"El PEX es flexible y se une mecánicamente con anillos de engargolado, conexiones de expansión o a presión, no con pegamento."},
  {"id":5,"q":"El tubo negro de ABS en un edificio se usa típicamente para:","opts":["Tubería de desagüe, residuales y ventilación","Agua caliente a presión","Suministro de gas natural","Agua potable fría a presión"],"re":"El ABS es un plástico negro común usado para tubería DWV (desagüe, residuales y ventilación), no para agua a presión."},
  {"id":6,"q":"El tubo de cobre para agua se une más comúnmente mediante:","opts":["Soldadura de solvente","Soldadura blanda (sweating) de la junta","Roscado del cobre blando","Engargolado en frío con cinta"],"re":"El tubo y las conexiones de cobre se unen comúnmente por soldadura blanda, llamada sweating, con fundente y soldadura."},
  {"id":7,"q":"Todo tubo de suministro usado para agua potable debe ser:","opts":["Pintado de azul","De al menos 2 pulgadas","Libre de plomo","Solo galvanizado"],"re":"El tubo, la soldadura y las conexiones de agua potable deben estar libres de plomo para proteger la calidad del agua."},
  {"id":8,"q":"Al conectar dos materiales de desagüe distintos como ABS y PVC, el método más confiable es:","opts":["Encintar la junta","Calentar ambos extremos y presionar","Roscar plástico en plástico","Usar una conexión o cople de transición aprobado"],"re":"Los plásticos distintos deben unirse con un cople de transición aprobado en lugar de mezclar sus cementos."},
  {"id":9,"q":"Comparado con los tipos K y L, el cobre tipo M tiene:","opts":["La pared más delgada de los tres","Una pared más gruesa que la K","Pared idéntica a la K","Ningún uso aprobado para agua"],"re":"El tipo M tiene la pared más delgada; algunas jurisdicciones limitan dónde puede usarse el tipo M para suministro de agua."},
  {"id":10,"q":"Cuando la presión estática del agua supera 80 psi, el código exige:","opts":["Un medidor de agua más grande","Un regulador de presión aprobado para reducirla a 80 psi o menos","Un segundo dispositivo antirretorno","Cambiar a tubo galvanizado"],"re":"Por encima de 80 psi, una válvula reductora aprobada debe bajar la presión estática a 80 psi o menos."},
  {"id":11,"q":"Un sistema de suministro de agua generalmente debe entregar una presión residual de al menos unos:","opts":["5 psi","60 psi","15 psi","100 psi"],"re":"Si la fuente no mantiene unos 15 psi residuales en el mueble, debe añadirse un tanque y bomba u otro medio."},
  {"id":12,"q":"Cuando se instala un regulador de presión en la acometida, el código también exige:","opts":["Una línea de derivación","Quitar todas las llaves de paso","Un segundo calentador de agua","Un tanque de expansión térmica aguas abajo"],"re":"Un sistema cerrado tras un regulador necesita un tanque de expansión para absorber la presión por expansión térmica."},
  {"id":13,"q":"El propósito principal de dimensionar correctamente la tubería de distribución de agua es:","opts":["Dar flujo y presión adecuados en cada mueble","Solo reducir el costo del material","Hacer todos los tubos del mismo tamaño","Eliminar la necesidad de válvulas"],"re":"El tubo debe dimensionarse para que cada mueble reciba suficiente flujo y presión cuando otros también se usan."},
  {"id":14,"q":"Una presión de agua excesivamente alta en un edificio tiende a:","opts":["Mejorar la vida de los muebles","Esforzar las conexiones y causar fugas y golpe de ariete","Bajar las facturas de agua","No tener efecto en el sistema"],"re":"La presión alta esfuerza juntas, válvulas y aparatos y favorece fugas y golpe de ariete, por eso se limita."},
  {"id":15,"q":"Un amortiguador de golpe de ariete se instala para:","opts":["Aumentar la presión estática","Filtrar sedimento","Amortiguar el choque cuando una válvula cierra rápido","Prevenir el retorno"],"re":"El amortiguador absorbe la sobrepresión que se produce cuando una válvula de cierre rápido detiene el agua, reduciendo el golpeteo."},
  {"id":16,"q":"Una llave de paso de apertura total en la acometida de agua existe principalmente para:","opts":["Reducir la presión","Calentar el agua","Ventilar el sistema","Permitir aislar el suministro del edificio para reparaciones"],"re":"Una llave principal permite cortar el agua de todo el edificio para mantenimiento o emergencias."},
  {"id":17,"q":"Las llaves de control de agua caliente y fría en un mueble deben disponerse de modo que, de frente al mueble:","opts":["La caliente a la izquierda y la fría a la derecha","Ambas a la derecha","La caliente a la derecha y la fría a la izquierda","La posición no importa"],"re":"Por convención la caliente va a la izquierda y la fría a la derecha en el mueble, como espera el usuario."},
  {"id":18,"q":"El sello líquido de un sifón de mueble no debe ser menor de:","opts":["1 pulgada","2 pulgadas","6 pulgadas","8 pulgadas"],"re":"El sello del sifón debe tener al menos 2 pulgadas (y no más de 4) para bloquear el gas de cloaca de forma confiable."},
  {"id":19,"q":"La función principal del sifón de un mueble es:","opts":["Acelerar el drenaje","Reducir el ruido del tubo","Retener agua que bloquea el gas de cloaca hacia la habitación","Filtrar sólidos"],"re":"El sello de agua del sifón evita que los gases de cloaca regresen por el mueble al interior del edificio."},
  {"id":20,"q":"A un desagüe horizontal de 3 pulgadas o menos generalmente se le da una pendiente mínima de unos:","opts":["1/16 de pulgada por pie","1 pulgada por pie","No se necesita pendiente","1/4 de pulgada por pie"],"re":"Los desagües horizontales pequeños suelen inclinarse cerca de 1/4 de pulgada por pie para que el residuo fluya por gravedad sin dejar sólidos."},
  {"id":21,"q":"Un sifón en S está prohibido en los muebles principalmente porque:","opts":["Puede autosifonarse y perder su sello de agua","Cuesta demasiado","Es muy pequeño","No se puede limpiar"],"re":"El sifón en S tiende a autosifonarse, vaciando el agua del sello y dejando entrar gas de cloaca; se usa un sifón en P bien ventilado."},
  {"id":22,"q":"Poner doble sifón a un solo mueble está:","opts":["Requerido para inodoros","No permitido","Recomendado para fregaderos","Solo para coladeras de piso"],"re":"Dos sifones en serie atrapan aire entre ellos y tienden a perder el sello, por eso el doble sifón está prohibido."},
  {"id":23,"q":"El propósito principal de una ventilación en el sistema DWV es:","opts":["Conducir agua residual","Aumentar la presión del agua","Admitir aire para que los sifones no se sifoneen y el drenaje fluya","Almacenar el rebose"],"re":"Las ventilaciones dejan entrar aire al sistema de drenaje para que fluya bien y los sellos de los sifones no se sifoneen ni se expulsen."},
  {"id":24,"q":"El desagüe y el brazo del sifón de un inodoro deben ser de al menos:","opts":["1-1/4 pulgada","1-1/2 pulgada","2 pulgadas","3 pulgadas"],"re":"Un inodoro requiere un desagüe y brazo de sifón de 3 pulgadas para manejar su descarga."},
  {"id":25,"q":"La tubería de ventilación debe inclinarse de modo que:","opts":["Drene de regreso al tubo de drenaje por gravedad","Atrape agua estancada","Quede perfectamente nivelada","Se incline en sentido contrario a la columna"],"re":"Las ventilaciones deben drenar cualquier condensado de regreso al desagüe por gravedad para que el agua no se acumule y bloquee la ventilación."},
  {"id":26,"q":"Un registro de limpieza se coloca en una línea de desagüe principalmente para:","opts":["Ventilar la línea","Dar acceso para desbloquear obstrucciones","Reducir el tamaño del tubo","Agregar un sifón"],"re":"El registro da acceso para varillar o limpiar obstrucciones en el desagüe sin cortar el tubo."},
  {"id":27,"q":"La válvula de alivio de temperatura y presión (T&P) de un calentador protege contra:","opts":["Baja presión de agua","Solo el retorno","Temperatura y presión excesivas en el tanque","Agua dura"],"re":"La válvula T&P abre si la temperatura o la presión suben demasiado, evitando una ruptura peligrosa del tanque."},
  {"id":28,"q":"El tubo de descarga de una válvula de alivio T&P debe:","opts":["Ser más pequeño que la salida de la válvula","Subir hacia un fregadero","Conectarse directo a la cloaca","Drenar por gravedad y no estar sifonado ni con válvula"],"re":"La línea de alivio debe ir a tamaño completo, drenar por gravedad, sin válvula ni sifón, y terminar en un punto aprobado."},
  {"id":29,"q":"Un espacio de aire (air gap) previene el retorno al:","opts":["Dejar un espacio vertical físico entre la salida y el borde de rebose","Agregar una válvula de retención","Aumentar la presión del agua","Agregar un sifón"],"re":"Un air gap es un espacio vertical sin obstrucción para que el agua contaminada no pueda sifonarse de regreso al suministro."},
  {"id":30,"q":"Un espacio de aire se mide desde la salida de suministro hacia abajo hasta:","opts":["El piso","El borde de rebose del mueble","El vertedero del sifón","La ventilación"],"re":"El air gap se mide verticalmente desde la abertura más baja de la salida hasta el borde de rebose del mueble."},
  {"id":31,"q":"Una llave de manguera que alimenta una manguera de jardín debe protegerse con:","opts":["Un regulador de presión","Un segundo sifón","Un rompevacío (vacuum breaker)","Un tubo más grande"],"re":"Un rompevacío de conexión de manguera evita que el agua contaminada se sifonee de regreso al suministro potable por la manguera."},
  {"id":32,"q":"Un conjunto antirretorno de principio de presión reducida (RP) se usa donde:","opts":["No existe peligro","Solo hay riesgos de bajo peligro y no de salud","La presión es menor de 15 psi","Debe protegerse una conexión cruzada de alto peligro"],"re":"Un conjunto RP da la mayor protección y se usa en conexiones cruzadas de alto peligro al agua potable."},
  {"id":33,"q":"Un calentador de agua instalado donde una fuga podría causar daño (como un ático) generalmente necesita:","opts":["Una charola de drenaje conectada a un punto aprobado","Una segunda válvula de alivio","Ninguna disposición especial","Un tiro más grande"],"re":"Una charola resistente a la corrosión con drenaje a un punto aprobado capta la fuga y protege la estructura de abajo."},
  {"id":34,"q":"Una conexión cruzada es peligrosa porque:","opts":["Baja la presión del agua","Puede dejar entrar agua no potable al suministro de agua potable","Aumenta el flujo","Desperdicia energía"],"re":"Una conexión cruzada une sistemas potable y no potable, permitiendo que la contaminación entre al agua potable si ocurre retorno."},
  {"id":35,"q":"Un material aprobado común para tubería de gas combustible es:","opts":["PVC","Cobre tipo M para residuales","Tubo de acero negro","ABS"],"re":"El acero negro (comúnmente cédula 40) es un material estándar para tubería de gas; el CSST también se usa mucho donde está listado."},
  {"id":36,"q":"Una trampa de sedimento (pierna de goteo) en un aparato de gas se instala para:","opts":["Reducir la presión del gas","Ventilar el gas","Aumentar el flujo","Captar suciedad y humedad antes de que lleguen al control del aparato"],"re":"La trampa de sedimento recoge suciedad y condensado para que no lleguen ni ensucien la válvula o el quemador del aparato."},
  {"id":37,"q":"Cada aparato de gas debe tener:","opts":["Una llave de cierre fácilmente accesible cerca del aparato","Sin cierre","Solo el cierre del medidor","Una válvula de alivio de presión"],"re":"Un cierre accesible del aparato permite cortar el gas en el aparato para servicio o emergencias."},
  {"id":38,"q":"La tubería de gas debe dimensionarse para poder suministrar:","opts":["Solo el aparato más pequeño","La demanda máxima combinada de los aparatos servidos","La mitad de la carga total","El doble de la capacidad del medidor"],"re":"La tubería se dimensiona para la suma del consumo máximo de los aparatos, de modo que todos puedan operar sin faltar gas."},
  {"id":39,"q":"La trampa de sedimento normalmente se ubica:","opts":["Solo en el medidor","En el techo","Aguas abajo del cierre del aparato, cerca de la entrada del aparato","Dentro del tiro del aparato"],"re":"Se coloca después de la llave de cierre y lo más cerca posible de la entrada del aparato para captar la suciedad antes del control."},
  {"id":40,"q":"CSST significa:","opts":["Tubo de suministro de acero fundido","Tubo de soldadura blanda recubierto","Trampa central de cierre de seguridad","Tubería corrugada de acero inoxidable"],"re":"CSST es tubería corrugada de acero inoxidable, un material de gas flexible y listado, instalado según su listado."},
  {"id":41,"q":"Un sistema nuevo de tubería de gas debe:","opts":["Probarse a presión en busca de fugas antes de ponerse en servicio","Llenarse con agua","Enterrarse antes de probarse","Dejarse abierto al aire"],"re":"La tubería de gas se prueba a presión para confirmar que aguanta sin fugas antes de abrir el gas."},
  {"id":42,"q":"Una válvula sísmica (de sismo) de cierre de gas está diseñada para:","opts":["Aumentar la presión del gas","Detener automáticamente el flujo de gas durante un sismo fuerte","Reemplazar el medidor","Ventilar gas al ático"],"re":"Una válvula sísmica de cierre cierra durante un movimiento fuerte del suelo para reducir el riesgo de incendios por gas tras un sismo."},
  {"id":43,"q":"El Código de Plomería de California (Título 24, Parte 5) se basa en el:","opts":["Código Residencial Internacional","Código Eléctrico Nacional","Código Uniforme de Plomería (UPC)","Solo una ordenanza municipal local"],"re":"El código de plomería de California adopta y enmienda el Código Uniforme de Plomería (UPC) de IAPMO."},
  {"id":44,"q":"En California, un calentador de agua residencial generalmente debe arriostrarse contra sismos con:","opts":["Sin correas","Solo cinta de plomero","Una sola correa arriba","Al menos dos correas, en el tercio superior y el inferior del tanque"],"re":"California exige sujetar el tanque en el tercio superior y el inferior para que no se vuelque en un sismo."},
  {"id":45,"q":"Por lo general se exige un permiso e inspección de plomería para que:","opts":["El trabajo se verifique contra el código por seguridad","La ciudad cobre más","Solo se beneficien los diseñadores con licencia","El permiso reemplace la inspección"],"re":"Los permisos e inspecciones verifican que la instalación cumpla el código, protegiendo la salud y la seguridad."},
  {"id":46,"q":"La clasificación de plomería C-36 autoriza a un contratista a:","opts":["Solo reparar grifos","Instalar y reparar suministro de agua, DWV, tubería de gas y calentadores","Hacer trabajo eléctrico","Construir cimientos"],"re":"La C-36 cubre suministrar agua segura y la disposición adecuada de residuos, incluyendo agua, DWV, gas y trabajo de calentadores."},
  {"id":47,"q":"La plomería de obra negra (rough-in) normalmente se inspecciona:","opts":["Después de cerrar y pintar los muros","Solo en la inspección final","Antes de quedar oculta por muros o relleno","Nunca"],"re":"La obra negra debe inspeccionarse mientras está expuesta para poder ver el trabajo antes de cubrirlo."},
  {"id":48,"q":"Un sistema de drenaje comúnmente se prueba de hermeticidad usando:","opts":["Solo una máquina de humo","Una hidrolavadora","Ninguna prueba","Una prueba de agua o de aire antes de aprobarlo"],"re":"La tubería DWV se prueba con agua o aire para confirmar que las juntas aguantan antes de aprobar el sistema."},
  {"id":49,"q":"Al excavar zanjas para tubo subterráneo, una preocupación clave de seguridad es:","opts":["El derrumbe de la zanja y el apuntalamiento o talud adecuado","El color de la pintura","La marca del tubo","El tamaño del medidor"],"re":"Las excavaciones pueden colapsar y sepultar a un trabajador, por eso las zanjas profundas requieren apuntalamiento, talud o blindaje."},
  {"id":50,"q":"Antes de excavar para una nueva línea de cloaca o agua, el contratista debe:","opts":["Excavar primero y revisar después","Llamar para localizar instalaciones enterradas","Ignorar otras instalaciones","Solo avisar a los vecinos"],"re":"Las instalaciones subterráneas deben localizarse y marcarse antes de excavar para no golpear líneas de gas, electricidad u otras."}
];
